<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Purchase Orders</h1><p class="text-muted mb-0">Order, approve, and receive stock into inventory.</p></div><button class="btn btn-primary" data-bs-toggle="modal" data-bs-target="#newPo"><i class="fa-solid fa-plus me-2"></i>New PO</button></div>
<div class="card"><div class="table-responsive"><table class="table align-middle mb-0"><thead><tr><th>PO</th><th>Vendor</th><th>Date</th><th>Status</th><th>Total</th><th>Created by</th><th></th></tr></thead><tbody><?php foreach($orders as $o):?><tr><td><strong><?=e($o['po_number'])?></strong></td><td><?=e($o['vendor_name'])?></td><td><?=e($o['order_date'])?></td><td><?=e($o['status'])?></td><td><?=money($o['total'])?></td><td><?=e($o['created_name'])?></td><td><div class="d-flex gap-1"><form method="post" action="/portal/purchase-orders/<?=$o['id']?>/status"><?=csrf_field()?><input type="hidden" name="status" value="approved"><button class="btn btn-sm btn-outline-primary">Approve</button></form><form method="post" action="/portal/purchase-orders/<?=$o['id']?>/receive"><?=csrf_field()?><button class="btn btn-sm btn-success">Receive</button></form></div></td></tr><?php endforeach?></tbody></table></div></div>
<div class="modal fade" id="newPo"><div class="modal-dialog modal-xl"><form class="modal-content" method="post" action="/portal/purchase-orders"><?=csrf_field()?><div class="modal-header"><h2 class="modal-title h5">New Purchase Order</h2><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="row g-3 mb-3"><div class="col-md-4"><label class="form-label">Vendor</label><input required class="form-control" name="vendor_name"></div><div class="col-md-4"><label class="form-label">Vendor email</label><input type="email" class="form-control" name="vendor_email"></div><div class="col-md-2"><label class="form-label">Order date</label><input type="date" class="form-control" name="order_date" value="<?=date('Y-m-d')?>"></div><div class="col-md-2"><label class="form-label">Expected</label><input type="date" class="form-control" name="expected_date"></div></div><table class="table" id="poLines"><thead><tr><th>Inventory item</th><th>Description</th><th>Qty</th><th>Unit cost</th></tr></thead><tbody><?php for($x=0;$x<4;$x++):?><tr><td><select class="form-select" name="inventory_item_id[]"><option value="">Non-stock</option><?php foreach($items as $i):?><option value="<?=$i['id']?>" data-cost="<?=e($i['unit_cost'])?>"><?=e($i['name'])?></option><?php endforeach?></select></td><td><input class="form-control" name="description[]"></td><td><input type="number" step=".01" class="form-control" name="quantity[]" value="1"></td><td><input type="number" step=".01" class="form-control" name="unit_cost[]" value="0"></td></tr><?php endfor?></tbody></table><div class="row g-3"><div class="col-md-2 ms-auto"><label class="form-label">Tax</label><input type="number" step=".01" class="form-control" name="tax" value="0"></div><div class="col-md-2"><label class="form-label">Shipping</label><input type="number" step=".01" class="form-control" name="shipping" value="0"></div><div class="col-12"><label class="form-label">Notes</label><textarea class="form-control" name="notes"></textarea></div></div></div><div class="modal-footer"><button class="btn btn-primary">Create PO</button></div></form></div></div>
